import boto3
from botocore.exceptions import ClientError

sqs = boto3.client('sqs')

def publish_sqs_message(queue_url, user_data):
    try:
        response = sqs.send_message(
            QueueUrl=queue_url,
            MessageBody=user_data
        )
        print(f"Message sent. Receipt Handle: {response['MessageId']}")
    except ClientError as e:
        print(e.response['Error']['Message'])

def lambda_handler(event, context):
    user_data = {
        'email': event['email'],
        'phone_number': event['phone_number'],
        'address': event['address']
    }
    
    queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789012/pii_queue'
    publish_sqs_message(queue_url, user_data)